class TestRateLimiting:
    """Export must be rate-limited on a per-user basis."""

    def test_first_request_within_limit_succeeds(
        self, export_service, hr_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = True
        result = export_service.export_csv(requesting_user=hr_admin_user)
        assert result.status == HTTPStatus.OK

    def test_request_beyond_limit_raises_or_returns_429(
        self, export_service, hr_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = False
        try:
            result = export_service.export_csv(requesting_user=hr_admin_user)
            assert result.status == HTTPStatus.TOO_MANY_REQUESTS
        except Exception as exc:  # noqa: BLE001
            assert "rate" in str(exc).lower() or "limit" in str(exc).lower()

    def test_rate_limiter_is_called_with_correct_user_id(
        self, export_service, hr_admin_user, rate_limiter
    ):
        export_service.export_csv(requesting_user=hr_admin_user)
        rate_limiter.is_allowed.assert_called_once_with(hr_admin_user["id"])

    def test_rate_limit_is_per_user_independent(
        self, employee_repository, rate_limiter
    ):
        """Exhausting one user's quota must not affect another user's quota."""
        from app.services.directory_export import DirectoryExportService  # noqa: PLC0415

        user_a = {"id": "user-a", "role": "hr-admin", "email": "a@company.com"}
        user_b = {"id": "user-b", "role": "hr-admin", "email": "b@company.com"}

        def side_effect(user_id):
            return user_id != user_a["id"]  # only user_a is blocked

        rate_limiter.is_allowed.side_effect = side_effect
        svc = DirectoryExportService(
            employee_repository=employee_repository,
            rate_limiter=rate_limiter,
        )

        # user_b should still succeed
        result_b = svc.export_csv(requesting_user=user_b)
        assert result_b.status == HTTPStatus.OK

        # user_a should be blocked
        try:
            result_a = svc.export_csv(requesting_user=user_a)
            assert result_a.status == HTTPStatus.TOO_MANY_REQUESTS
        except Exception:  # noqa: BLE001
            pass  # raising is also acceptable

    def test_rate_limit_response_includes_retry_after_header(
        self, export_service, hr_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = False
        try:
            result = export_service.export_csv(requesting_user=hr_admin_user)
            if result.status == HTTPStatus.TOO_MANY_REQUESTS:
                assert "Retry-After" in result.headers
        except Exception:  # noqa: BLE001
            pass  # header check only relevant when service returns HTTP response

    def test_rate_limit_counter_increments_on_each_call(
        self, export_service, hr_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = True
        for _ in range(3):
            export_service.export_csv(requesting_user=hr_admin_user)
        assert rate_limiter.is_allowed.call_count == 3

    def test_different_users_checked_independently(
        self, export_service, rate_limiter
    ):
        user_1 = {"id": "user-hr-001", "role": "hr-admin", "email": "hr1@company.com"}
        user_2 = {"id": "user-hr-002", "role": "hr-admin", "email": "hr2@company.com"}
        rate_limiter.is_allowed.return_value = True

        export_service.export_csv(requesting_user=user_1)
        export_service.export_csv(requesting_user=user_2)

        calls = [call.args[0] for call in rate_limiter.is_allowed.call_args_list]
        assert user_1["id"] in calls
        assert user_2["id"] in calls

    @pytest.mark.parametrize("limit", [1, 5, 10])
    def test_requests_succeed_up_to_limit_then_blocked(
        self, employee_repository, limit
    ):
        """Simulate a real counter-based rate limiter."""
        from app.services.directory_export import DirectoryExportService  # noqa: PLC0415

        call_count = {"n": 0}

        real_limiter = MagicMock()

        def is_allowed(user_id):  # noqa: ARG001
            call_count["n"] += 1
            return call_count["n"] <= limit

        real_limiter.is_allowed.side_effect = is_allowed
        svc = DirectoryExportService(
            employee_repository=employee_repository,
            rate_limiter=real_limiter,
        )
        user = {"id": "user-test", "role": "hr-admin", "email": "test@company.com"}

        for i in range(limit):
            result = svc.export_csv(requesting_user=user)
            assert result.status == HTTPStatus.OK, f"Request {i + 1} should succeed"

        # Next request should be blocked
        try:
            over_limit = svc.export_csv(requesting_user=user)
            assert over_limit.status == HTTPStatus.TOO_MANY_REQUESTS
        except Exception:  # noqa: BLE001
            pass  # raising is acceptable


