class TestEndToEndScenarios:
    """Higher-level scenarios combining multiple concerns."""

    def test_mixed_employee_list_correct_redaction_and_format(
        self,
        export_service,
        hr_admin_user,
        opted_in_employee,
        opted_out_employee,
        another_opted_out_employee,
    ):
        result = export_service.export_csv(requesting_user=hr_admin_user)
        assert result.status == HTTPStatus.OK
        rows = parse_csv(result.body)
        assert len(rows) == 3

        by_id = {r["id"]: r for r in rows}

        # Opted-in
        for field in PII_FIELDS:
            assert by_id[opted_in_employee["id"]][field] != REDACTED_PLACEHOLDER

        # Opted-out
        for emp in (opted_out_employee, another_opted_out_employee):
            for field in PII_FIELDS:
                assert by_id[emp["id"]][field] == REDACTED_PLACEHOLDER

    def test_repeated_exports_by_same_admin_up_to_limit(
        self, export_service, hr_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = True
        results = [
            export_service.export_csv(requesting_user=hr_admin_user) for _ in range(5)
        ]
        assert all(r.status == HTTPStatus.OK for r in results)

    def test_export_blocked_after_limit_exceeded(
        self, export_service, hr_admin_user, rate_limiter
    ):
        call_count = {"n": 0}
        limit = 3

        def is_allowed(user_id):  # noqa: ARG001
            call_count["n"] += 1
            return call_count["n"] <= limit

        rate_limiter.is_allowed.side_effect = is_allowed

        for _ in range(limit):
            result = export_service.export_csv(requesting_user=hr_admin_user)
            assert result.status == HTTPStatus.OK

        try:
            blocked = export_service.export_csv(requesting_user=hr_admin_user)
            assert blocked.status == HTTPStatus.TOO_MANY_REQUESTS
        except Exception:  # noqa: BLE001
            pass  # raising is acceptable

    def test_non_admin_blocked_regardless_of_rate_limit(
        self, export_service, non_admin_user, rate_limiter
    ):
        rate_limiter.is_allowed.return_value = True  # rate limit would allow it
        with pytest.raises(PermissionError):
            export_service.export_csv(requesting_user=non_admin_user)
